// Solution
import sys
from typing import List
class Solution:
    def fibonacci(self, n: int) -> list[int]:
        if n == 1:
            return [0]
        result = [0, 1]
        for i in range(2, n):
            result.append(result[i - 1] + result[i - 2])
        return result
if __name__ == '__main__':
    n = int(input())
    solution = Solution()
    result = solution.fibonacci(n)
    print(' '.join(map(str, result)))

